import React, { useState, useEffect } from 'react';
import {
  Card,
  Row,
  Col,
  Button,
  Select,
  Table,
  Tag,
  Progress,
  Typography,
  Space,
  Alert,
  Spin,
  Modal,
  Tabs,
  Descriptions,
  message,
  Switch,
  Tooltip,
  Badge,
  Input,
  Form
} from 'antd';
import {
  PlayCircleOutlined,
  PauseCircleOutlined,
  StopOutlined,
  EyeOutlined,
  MonitorOutlined,
  VideoCameraOutlined,
  DatabaseOutlined,
  SettingOutlined,
  ReloadOutlined,
  ControlOutlined
} from '@ant-design/icons';
import ReactECharts from 'echarts-for-react';
import RTSPVideoPlayer from '../components/RTSPVideoPlayer';
import { aiExperimenterApi, experimentDataApi } from '../services/api';
import {
  Experiment,
  Formula,
  ExperimentStatus,
  MonitoringData
} from '../types';

const { Title, Paragraph, Text } = Typography;
const { Option } = Select;
const { TabPane } = Tabs;
const { TextArea } = Input;

const AIExperimenterPage: React.FC = () => {
  const [formulas, setFormulas] = useState<Formula[]>([]);
  const [experiments, setExperiments] = useState<Experiment[]>([]);
  const [selectedFormula, setSelectedFormula] = useState<number | null>(null);
  const [runningExperiment, setRunningExperiment] = useState<Experiment | null>(null);
  const [experimentStatus, setExperimentStatus] = useState<{ experiment: Experiment; monitoring_data: any; session_info?: { experiment_id: number; runtime_seconds: number; data_points_collected: number; last_update: number } } | null>(null);
  const [monitoringData, setMonitoringData] = useState<MonitoringData | null>(null);
  const [loading, setLoading] = useState(false);
  const [statusModalVisible, setStatusModalVisible] = useState(false);
  const [monitoringModalVisible, setMonitoringModalVisible] = useState(false);
  const [formulaDetailModalVisible, setFormulaDetailModalVisible] = useState(false);
  const [selectedFormulaDetail, setSelectedFormulaDetail] = useState<Formula | null>(null);
  const [experimentDetailModalVisible, setExperimentDetailModalVisible] = useState(false);
  const [selectedExperimentDetail, setSelectedExperimentDetail] = useState<Experiment | null>(null);
  const [statusInterval, setStatusInterval] = useState<NodeJS.Timeout | null>(null);

  // 视频源模式：'local' (本地摄像头) | 'rtsp' (海康威视RTSP)
  const [videoMode, setVideoMode] = useState<'local' | 'rtsp'>('rtsp');

  // 真实实验数据相关状态
  const [useRealData, setUseRealData] = useState(false);
  const [availableExperiments, setAvailableExperiments] = useState<Array<{id: string; name: string; created_date: string}>>([]);
  const [selectedRealExperiment, setSelectedRealExperiment] = useState<string | null>(null);
  const [realVoltageData, setRealVoltageData] = useState<any[]>([]);
  const [realChargeData, setRealChargeData] = useState<any[]>([]);
  const [realImpedanceData, setRealImpedanceData] = useState<any[]>([]);
  const [experimentSummary, setExperimentSummary] = useState<any>(null);
  const [dataLoading, setDataLoading] = useState(false);
  const [dbConfigModalVisible, setDbConfigModalVisible] = useState(false);

  // 参数确认Modal状态
  const [parameterConfirmModalVisible, setParameterConfirmModalVisible] = useState(false);
  const [parsedParameters, setParsedParameters] = useState<any>(null);
  const [editedParameters, setEditedParameters] = useState<any>(null);

  // 充放电曲线视图状态
  const [chartViewType, setChartViewType] = useState<'overview' | 'detailed'>('overview');
  const [selectedCycle, setSelectedCycle] = useState<number | null>(null);

  // 当切换到详细视图时，自动选择第一个可用循环
  useEffect(() => {
    if (chartViewType === 'detailed' && !selectedCycle) {
      let cycles: number[] = [];
      if (useRealData && realChargeData.length > 0) {
        cycles = realChargeData.map(item => item.cycle_number);
      } else {
        cycles = [1, 2, 3, 5, 10, 15, 20, 25, 30, 40, 50, 60, 75, 100, 125, 150, 200];
      }
      if (cycles.length > 0) {
        setSelectedCycle(cycles.sort((a, b) => a - b)[0]);
      }
    }
  }, [chartViewType, selectedCycle, useRealData, realChargeData]);

  useEffect(() => {
    loadFormulas();
    loadExperiments();
    if (useRealData) {
      loadAvailableExperiments();
    }
    // 加载RTSP摄像头状态
    if (videoMode === 'rtsp') {
      loadRtspCameraStatus();
      // 自动启动所有RTSP摄像头
      setTimeout(() => {
        startAllRtspCameras();
      }, 2000); // 延迟2秒启动，确保页面完全加载
    }
  }, [useRealData, videoMode]);

  // 清理定时器和摄像头资源
  useEffect(() => {
    return () => {
      if (statusInterval) {
        clearInterval(statusInterval);
      }
      stopCameras();
      // 停止RTSP摄像头
      if (videoMode === 'rtsp') {
        aiExperimenterApi.stopRTSPCamera().catch(console.error);
      }
    };
  }, [statusInterval, videoMode]);

  const loadFormulas = async () => {
    // 直接使用模拟数据，确保表格有内容显示
    const mockFormulas = [
      {
        id: 1,
        name: '高能量密度正极电解液',
        system_type: '正极' as const,
        application_scenario: '3C',
        generation_method: 'initial_design' as const,
        description: '适用于高能量密度电池的正极电解液配方',
        components: [
          { component_type: 'positive_electrode', name: 'NCM811' },
          { component_type: 'negative_electrode', name: '石墨' },
          { component_type: 'solvent', name: 'EC:EMC (3:7)' },
          { component_type: 'salt', name: 'LiPF6' },
          { component_type: 'additive', name: 'FEC' }
        ],
        created_at: new Date('2025-10-15').toISOString()
      },
      {
        id: 2,
        name: '长寿命储能电池电解液',
        system_type: '正极' as const,
        application_scenario: '蓄能',
        generation_method: 'bayesian_opt' as const,
        description: '适用于储能系统的长寿命电解液配方',
        components: [
          { component_type: 'positive_electrode', name: 'LFP' },
          { component_type: 'negative_electrode', name: '石墨' },
          { component_type: 'solvent', name: 'PC:EMC (3:7)' },
          { component_type: 'salt', name: 'LiBF4' },
          { component_type: 'additive', name: 'VC' }
        ],
        created_at: new Date('2025-10-20').toISOString()
      },
      {
        id: 3,
        name: '动力电池高倍率电解液',
        system_type: '正极' as const,
        application_scenario: '动力',
        generation_method: 'redesign' as const,
        description: '适用于动力电池的高倍率充放电电解液配方',
        components: [
          { component_type: 'positive_electrode', name: 'NCA' },
          { component_type: 'negative_electrode', name: '硅碳' },
          { component_type: 'solvent', name: 'FEC:DEC (1:4)' },
          { component_type: 'salt', name: 'LiFSI' },
          { component_type: 'additive', name: 'DTD' }
        ],
        created_at: new Date('2025-10-10').toISOString()
      },
      {
        id: 4,
        name: '高电压电解液配方',
        system_type: '正极' as const,
        application_scenario: '3C',
        generation_method: 'initial_design' as const,
        description: '适用于高电压电池的电解液配方',
        components: [
          { component_type: 'positive_electrode', name: 'LiCoO2' },
          { component_type: 'negative_electrode', name: '钛酸锂' },
          { component_type: 'solvent', name: 'EC:DEC (1:1)' },
          { component_type: 'salt', name: 'LiTFSI' },
          { component_type: 'additive', name: 'PS' }
        ],
        created_at: new Date('2025-10-25').toISOString()
      },
      {
        id: 5,
        name: '低温电解液配方',
        system_type: '正极' as const,
        application_scenario: '3C',
        generation_method: 'bayesian_opt' as const,
        description: '适用于低温环境的电解液配方',
        components: [
          { component_type: 'positive_electrode', name: 'NCM622' },
          { component_type: 'negative_electrode', name: '硬碳' },
          { component_type: 'solvent', name: 'EC:DMC (1:1)' },
          { component_type: 'salt', name: 'LiPF6' },
          { component_type: 'additive', name: 'LiPO2F2' }
        ],
        created_at: new Date('2025-10-05').toISOString()
      },
      {
        id: 6,
        name: '锂硫电池电解液配方',
        system_type: '正极' as const,
        application_scenario: '3C',
        generation_method: 'redesign' as const,
        description: '专为锂硫电池设计的电解液配方',
        components: [
          { component_type: 'positive_electrode', name: '硫碳复合物' },
          { component_type: 'negative_electrode', name: '锂金属' },
          { component_type: 'solvent', name: 'DOL:DME (1:1)' },
          { component_type: 'salt', name: 'LiTFSI' },
          { component_type: 'additive', name: 'LiNO3' }
        ],
        created_at: new Date('2025-10-15').toISOString()
      },
      {
        id: 7,
        name: '固态电池界面电解液',
        system_type: '正极' as const,
        application_scenario: '3C',
        generation_method: 'initial_design' as const,
        description: '固态电池界面优化电解液配方',
        components: [
          { component_type: 'positive_electrode', name: 'NCM811' },
          { component_type: 'negative_electrode', name: '金属锂' },
          { component_type: 'solvent', name: 'EC:EMC (4:6)' },
          { component_type: 'salt', name: 'LiFSI' },
          { component_type: 'additive', name: 'FEC, TMSP' }
        ],
        created_at: new Date('2025-10-20').toISOString()
      }
    ];
    setFormulas(mockFormulas as any);
  };

  // 加载真实实验数据
  const loadAvailableExperiments = async () => {
    try {
      const response = await experimentDataApi.getExperimentList();
      if (response.success) {
        setAvailableExperiments(response.data.data);
      }
    } catch (error) {
      console.error('加载实验列表失败:', error);
      message.error('无法连接到实验数据库，将使用模拟数据');
    }
  };

  const loadRealExperimentData = async (experimentId: string) => {
    if (!experimentId) return;

    setDataLoading(true);
    try {
      // 并行加载所有数据
      const [voltageResponse, chargeResponse, impedanceResponse, summaryResponse] = await Promise.all([
        experimentDataApi.getResistanceVoltageData({
          experiment_id: experimentId,
          cycle_numbers: [1, 2, 10, 25, 50, 100]
        }),
        experimentDataApi.getChargeDischargeData({
          experiment_id: experimentId
        }),
        experimentDataApi.getImpedanceData({
          experiment_id: experimentId,
          current_threshold: 0.1
        }),
        experimentDataApi.getExperimentSummary(experimentId)
      ]);

      if (voltageResponse.success) {
        setRealVoltageData(voltageResponse.data.data);
      }

      if (chargeResponse.success) {
        setRealChargeData(chargeResponse.data.data);
      }

      if (impedanceResponse.success) {
        setRealImpedanceData(impedanceResponse.data.data);
      }

      if (summaryResponse.success) {
        setExperimentSummary(summaryResponse.data.data);
      }

      message.success(`成功加载实验 ${experimentId} 的数据`);
    } catch (error) {
      console.error('加载真实实验数据失败:', error);
      message.error('加载实验数据失败，请检查数据库连接');
    } finally {
      setDataLoading(false);
    }
  };

  const loadExperiments = async () => {
    // 直接使用模拟实验数据
    const mockExperiments = [
      {
        id: 1001,
        name: '高能量密度电池性能测试-20251015',
        formula_id: 1,
        status: 'completed',
        created_at: new Date('2025-10-15T09:30:00').toISOString(),
        completed_at: new Date('2025-10-15T16:45:00').toISOString(),
        results: {
          energy_density: 285,
          cycle_life: 1200,
          efficiency: 99.5
        }
      },
      {
        id: 1002,
        name: '长寿命储能电池循环测试-20251020',
        formula_id: 2,
        status: 'completed',
        created_at: new Date('2025-10-20T14:15:00').toISOString(),
        completed_at: new Date('2025-10-27T10:30:00').toISOString(),
        results: {
          energy_density: 245,
          cycle_life: 3500,
          efficiency: 99.2
        }
      },
      {
        id: 1003,
        name: '动力电池倍率性能测试-20251025',
        formula_id: 3,
        status: 'running',
        created_at: new Date('2025-10-25T11:00:00').toISOString(),
        completed_at: null,
        results: null
      },
      {
        id: 1004,
        name: '高电压电池稳定性测试-20251028',
        formula_id: 4,
        status: 'completed',
        created_at: new Date('2025-10-28T08:45:00').toISOString(),
        completed_at: new Date('2025-11-02T15:20:00').toISOString(),
        results: {
          energy_density: 310,
          cycle_life: 950,
          efficiency: 98.8
        }
      },
      {
        id: 1005,
        name: '低温电池性能测试-20251101',
        formula_id: 5,
        status: 'failed',
        created_at: new Date('2025-11-01T13:30:00').toISOString(),
        completed_at: new Date('2025-11-01T18:45:00').toISOString(),
        results: null,
        error_message: '低温环境下电池容量衰减过快'
      },
      {
        id: 1006,
        name: '锂硫电池充放电测试-20251105',
        formula_id: 6,
        status: 'running',
        created_at: new Date('2025-11-05T10:15:00').toISOString(),
        completed_at: null,
        results: null
      },
      {
        id: 1007,
        name: '固态电池界面测试-20251108',
        formula_id: 7,
        status: 'pending',
        created_at: new Date('2025-11-08T09:00:00').toISOString(),
        completed_at: null,
        results: null
      },
      {
        id: 1008,
        name: '高能量密度电池二次验证-20251110',
        formula_id: 1,
        status: 'completed',
        created_at: new Date('2025-11-10T15:30:00').toISOString(),
        completed_at: new Date('2025-11-17T12:15:00').toISOString(),
        results: {
          energy_density: 288,
          cycle_life: 1180,
          efficiency: 99.6
        }
      }
    ];
    setExperiments(mockExperiments as any);
  };

  // 解析需求参数
  const handleParseRequirements = async (userInput: string, experimentName: string) => {
    try {
      const response = await fetch('http://localhost:5008/api/ai-experimenter/parse_requirements', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          user_input: userInput,
          experiment_name: experimentName
        }),
      });

      const data = await response.json();
      if (data.success) {
        setParsedParameters(data.parsed_requirements);
        setEditedParameters(data.parsed_requirements);
        setParameterConfirmModalVisible(true);
      } else {
        message.error('解析需求失败');
      }
    } catch (error) {
      console.error('解析需求失败:', error);
      message.error('解析需求时发生错误');
    }
  };

  // 执行实验
  const handleExecuteExperiment = async () => {
    if (!selectedFormula) {
      Modal.warning({
        title: '请选择配方',
        content: '请先选择一个配方才能执行实验'
      });
      return;
    }

    // 显示需求输入对话框
    Modal.confirm({
      title: '输入实验需求',
      content: (
        <div>
          <p>请描述您的实验需求，系统将自动解析参数：</p>
          <TextArea
            placeholder="例如：我需要做一个锂离子电池电解液实验，目标电压3.7V，温度25°C，浓度1.5mol/L"
            rows={4}
            id="requirement-input"
          />
        </div>
      ),
      onOk: () => {
        const userInput = (document.getElementById('requirement-input') as HTMLTextAreaElement)?.value;
        if (userInput) {
          handleParseRequirements(userInput, `实验_${new Date().toLocaleString()}`);
        }
      }
    });
  };

  // 确认参数并执行实验
  const handleConfirmParameters = async () => {
    if (!selectedFormula || !editedParameters) {
      return;
    }

    setLoading(true);
    setParameterConfirmModalVisible(false);

    try {
      const response = await fetch('http://localhost:5008/api/ai-experimenter/execute', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          formula_id: selectedFormula,
          experiment_name: editedParameters.experiment_name,
          user_requirements: editedParameters
        }),
      });

      const data = await response.json();
      if (data.success) {
        const newExperiment = {
          id: data.experiment_id,
          name: editedParameters.experiment_name,
          formula_id: selectedFormula,
          status: 'running',
          created_at: new Date().toISOString()
        };

        setRunningExperiment(newExperiment as any);
        setExperiments(prev => [newExperiment as any, ...prev]);
        startStatusMonitoring(data.experiment_id);

        Modal.success({
          title: '实验启动成功',
          content: `实验 ${editedParameters.experiment_name} 已开始执行`
        });
      } else {
        message.error(data.error || '启动实验失败');
