            const deltaI = Math.abs(curr.current - prev.current);
            const impedance = deltaV / deltaI * 1000; // 转换为mΩ
            impedanceData.push({
              cycle: curr.cycle,
              impedance: impedance.toFixed(2),
              time: curr.time
            });
          }
        }
        return impedanceData;
      };

