    {
      title: '配方ID',
      dataIndex: 'formula_id',
      key: 'formula_id',
      width: 80
    },
    {
      title: '创建时间',
      dataIndex: 'created_at',
      key: 'created_at',
      width: 150,
      render: (date: string) => new Date(date).toLocaleString()
    },
