      {/* 监控数据模态框 */}
      <Modal
        title="实验过程监控数据"
        visible={monitoringModalVisible}
        onCancel={() => setMonitoringModalVisible(false)}
        footer={null}
        width={1200}
      >
        <Tabs>
          <TabPane tab="配方信息" key="formula_info">
            {(() => {
              // 获取当前正在运行实验的配方信息
              const currentFormula = runningExperiment ?
                formulas.find(f => f.id === (runningExperiment as any).formula_id) :
                formulas[0]; // 如果没有运行中的实验，显示第一个配方作为示例

              if (!currentFormula || !currentFormula.components) {
                return (
                  <Row gutter={16} style={{ marginBottom: 16 }}>
                    <Col span={24}>
                      <Card title="当前配方详细信息" size="small">
                        <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
                          无配方信息
                        </div>
                      </Card>
                    </Col>
                  </Row>
                );
              }

              // 按类型分组配方组分
              const components = currentFormula.components;
              const solvents = components.filter(comp => comp.component_type === 'solvent');
              const salts = components.filter(comp => comp.component_type === 'salt');
              const additives = components.filter(comp => comp.component_type === 'additive');
              // 由于Component类型定义中没有电极类型，我们从模拟数据中处理
              const electrodes = components.filter(comp =>
                (comp as any).component_type === 'positive_electrode' || (comp as any).component_type === 'negative_electrode'
              );

              // 渲染配方组分的辅助函数
              const renderComponent = (component: any, color: string) => (
                <div style={{
                  padding: '12px',
                  backgroundColor: '#f0f2f5',
                  borderRadius: '6px',
                  marginBottom: '8px'
                }}>
                  <div style={{ fontWeight: 'bold', marginBottom: '8px', color: color }}>
                    {component.name}
                  </div>
                  <div style={{ fontSize: '14px', lineHeight: '1.5' }}>
                    <p><Text strong>浓度/比例：</Text>{component.concentration || 'N/A'} {component.unit || ''}</p>
                    {component.chemical_formula && (
                      <p><Text strong>化学式：</Text>{component.chemical_formula}</p>
                    )}
                    {component.source && (
                      <p><Text strong>来源：</Text>{component.source}</p>
                    )}
                    {component.properties && typeof component.properties === 'object' && (
                      <div>
                        <Text strong>性质：</Text>
                        <div style={{ marginLeft: '8px', fontSize: '12px', color: '#666' }}>
                          {Object.entries(component.properties).map(([key, value]) => (
                            <div key={key}>{key}: {String(value)}</div>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              );

              return (
                <Row gutter={16} style={{ marginBottom: 16 }}>
                  <Col span={24}>
                    <Card title={`当前配方详细信息 - ${currentFormula.name}`} size="small">
                      <div>
                        <p><Text strong>配方名称：</Text>{currentFormula.name}</p>
                        <p><Text strong>体系类型：</Text>{currentFormula.system_type}</p>
                        <p><Text strong>应用场景：</Text>{currentFormula.application_scenario}</p>
                        <p><Text strong>生成方法：</Text>
                          <Tag color="blue">{currentFormula.generation_method}</Tag>
                        </p>
                        {currentFormula.description && (
                          <p><Text strong>描述：</Text>{currentFormula.description}</p>
                        )}

                        <div style={{ marginTop: 16 }}>
                          <Text strong>配方组分构成：</Text>
                          <div style={{ marginTop: 12 }}>
                            <Row gutter={16}>
                              {/* 溶剂 */}
                              {solvents.length > 0 && (
                                <Col span={8}>
                                  <div style={{ marginBottom: '12px' }}>
                                    <div style={{
                                      fontWeight: 'bold',
                                      marginBottom: '8px',
                                      color: '#1890ff',
                                      fontSize: '14px'
                                    }}>
                                      溶剂体系 ({solvents.length}种)
                                    </div>
                                    {solvents.map((solvent, index) => renderComponent(solvent, '#1890ff'))}
                                  </div>
                                </Col>
                              )}

                              {/* 电解质盐 */}
                              {salts.length > 0 && (
                                <Col span={8}>
                                  <div style={{ marginBottom: '12px' }}>
                                    <div style={{
                                      fontWeight: 'bold',
                                      marginBottom: '8px',
                                      color: '#52c41a',
                                      fontSize: '14px'
                                    }}>
                                      电解质盐 ({salts.length}种)
                                    </div>
                                    {salts.map((salt, index) => renderComponent(salt, '#52c41a'))}
                                  </div>
                                </Col>
                              )}

                              {/* 功能添加剂 */}
                              {additives.length > 0 && (
                                <Col span={8}>
                                  <div style={{ marginBottom: '12px' }}>
                                    <div style={{
                                      fontWeight: 'bold',
                                      marginBottom: '8px',
                                      color: '#faad14',
                                      fontSize: '14px'
                                    }}>
                                      功能添加剂 ({additives.length}种)
                                    </div>
                                    {additives.map((additive, index) => renderComponent(additive, '#faad14'))}
                                  </div>
                                </Col>
                              )}
                            </Row>

                            {/* 电极材料 */}
                            {electrodes.length > 0 && (
                              <Row gutter={16} style={{ marginTop: 12 }}>
                                <Col span={24}>
                                  <div style={{ marginBottom: '12px' }}>
                                    <div style={{
                                      fontWeight: 'bold',
                                      marginBottom: '8px',
                                      color: '#722ed1',
                                      fontSize: '14px'
                                    }}>
                                      电极材料 ({electrodes.length}种)
                                    </div>
                                    <Row gutter={16}>
                                      {electrodes.map((electrode, index) => (
                                        <Col span={12} key={index}>
                                          {renderComponent(electrode, '#722ed1')}
                                        </Col>
                                      ))}
                                    </Row>
                                  </div>
                                </Col>
                              </Row>
                            )}

                            {/* 配方汇总信息 */}
                            <Row gutter={16} style={{ marginTop: 16 }}>
                              <Col span={24}>
                                <Card size="small" style={{ backgroundColor: '#fafafa' }}>
                                  <div style={{ fontWeight: 'bold', marginBottom: '8px' }}>
                                    配方汇总统计
                                  </div>
                                  <Row gutter={16}>
                                    <Col span={6}>
                                      <div style={{ textAlign: 'center' }}>
                                        <div style={{ fontSize: '16px', color: '#1890ff' }}>
                                          {solvents.length}
                                        </div>
                                        <div style={{ fontSize: '12px', color: '#666' }}>溶剂种类</div>
                                      </div>
                                    </Col>
                                    <Col span={6}>
                                      <div style={{ textAlign: 'center' }}>
                                        <div style={{ fontSize: '16px', color: '#52c41a' }}>
                                          {salts.length}
                                        </div>
                                        <div style={{ fontSize: '12px', color: '#666' }}>电解质盐种类</div>
                                      </div>
                                    </Col>
                                    <Col span={6}>
                                      <div style={{ textAlign: 'center' }}>
                                        <div style={{ fontSize: '16px', color: '#faad14' }}>
                                          {additives.length}
                                        </div>
                                        <div style={{ fontSize: '12px', color: '#666' }}>添加剂种类</div>
                                      </div>
                                    </Col>
                                    <Col span={6}>
                                      <div style={{ textAlign: 'center' }}>
                                        <div style={{ fontSize: '16px', color: '#722ed1' }}>
                                          {components.length}
                                        </div>
                                        <div style={{ fontSize: '12px', color: '#666' }}>总组分数</div>
                                      </div>
                                    </Col>
                                  </Row>
                                </Card>
                              </Col>
                            </Row>
                          </div>
                        </div>
                      </div>
                    </Card>
                  </Col>
                </Row>
              );
            })()}
