                    <div style={{ marginBottom: 12 }}>
                      <Text strong>浸润完成度：</Text>
                      <Progress percent={88} status="active" style={{ marginTop: 4 }} />
                    </div>
                    <div style={{ marginBottom: 12 }}>
                      <Text strong>密封性测试：</Text>
                      <Progress percent={100} status="success" style={{ marginTop: 4 }} />
                    </div>
                    <div style={{ marginTop: 16, padding: '12px', backgroundColor: '#f6ffed', borderRadius: '6px' }}>
                      <div style={{ fontWeight: 'bold', marginBottom: '8px', color: '#52c41a' }}>关键指标</div>
                      <p>保持率: 98.5%</p>
                      <p>平均注液时间: 45秒/电池</p>
                      <p>不良率: 0.2%</p>
                    </div>
                  </div>
                </Card>
              </Col>
            </Row>
          </TabPane>
          <TabPane tab="内阻/电压数据" key="impedance_voltage">
            <Row gutter={16} style={{ marginBottom: 16 }}>
              <Col span={12}>
                <Card title="内阻实时监控" size="small">
                  <div style={{ marginBottom: 16 }}>
                    <ReactECharts option={renderImpedanceChart()} style={{ height: '250px' }} />
                  </div>
                  <div>
                    <Row gutter={8}>
                      <Col span={12}>
                        <p><Text strong>初始阻抗：</Text> 15.2 mΩ</p>
                        <p><Text strong>电荷转移电阻：</Text> 8.3 mΩ</p>
                      </Col>
                      <Col span={12}>
                        <p><Text strong>韦伯阻抗：</Text> 6.9 mΩ</p>
                        <p><Text strong>阻抗增长：</Text> 22.5%</p>
                      </Col>
                    </Row>
                  </div>
                </Card>
              </Col>
              <Col span={12}>
                <Card title="电压监控" size="small">
                  <div style={{ marginBottom: 16 }}>
                    <ReactECharts option={renderVoltageChart()} style={{ height: '250px' }} />
                  </div>
                  <div>
                    <Row gutter={8}>
                      <Col span={12}>
                        <p><Text strong>标称电压：</Text> 3.7 V</p>
                        <p><Text strong>充电截止：</Text> 4.2 V</p>
                      </Col>
                      <Col span={12}>
                        <p><Text strong>放电截止：</Text> 2.5 V</p>
                        <p><Text strong>电压滞后：</Text> 0.15 V</p>
                      </Col>
                    </Row>
                  </div>
                </Card>
              </Col>
            </Row>
          </TabPane>
          <TabPane tab="充放电曲线" key="charge_discharge">
            <Row gutter={16} style={{ marginBottom: 16 }}>
              <Col span={24}>
                <Card
                  title="充放电曲线实时监控"
                  size="small"
                  extra={
                    <Space>
                      <span>视图类型：</span>
                      <Select
                        value={chartViewType}
                        onChange={setChartViewType}
                        style={{ width: 120 }}
                      >
                        <Option value="overview">整体视图</Option>
                        <Option value="detailed">详细视图</Option>
                      </Select>
                      {chartViewType === 'detailed' && (
                        <>
                          <span>循环选择：</span>
                          <Select
                            value={selectedCycle}
                            onChange={setSelectedCycle}
                            style={{ width: 120 }}
                            placeholder="选择循环"
                            showSearch
                            filterOption={(input, option) =>
                              (option?.label as string)?.toLowerCase().includes(input.toLowerCase())
                            }
                          >
                            {getAvailableCycles().map(cycle => (
                              <Option key={cycle} value={cycle}>
                                第{cycle}次循环
                              </Option>
                            ))}
                          </Select>
                        </>
                      )}
                    </Space>
                  }
                >
                  <div style={{ marginBottom: 16 }}>
                    <ReactECharts
                      option={renderChargeDischargeCurveChart()}
                      style={{ height: '400px' }}
                    />
                  </div>
                  {chartViewType === 'overview' && (
                    <div>
                      <Row gutter={16}>
                        <Col span={8}>
                          <div style={{ textAlign: 'center', padding: '12px', backgroundColor: '#f0f2f5', borderRadius: '6px' }}>
                            <div style={{ fontSize: '16px', fontWeight: 'bold', color: '#1890ff' }}>充电容量</div>
                            <div style={{ fontSize: '20px', margin: '8px 0' }}>2800 mAh</div>
                            <div style={{ fontSize: '12px', color: '#666' }}>设计容量: 2850 mAh</div>
                          </div>
                        </Col>
                        <Col span={8}>
                          <div style={{ textAlign: 'center', padding: '12px', backgroundColor: '#f0f2f5', borderRadius: '6px' }}>
                            <div style={{ fontSize: '16px', fontWeight: 'bold', color: '#52c41a' }}>放电容量</div>
                            <div style={{ fontSize: '20px', margin: '8px 0' }}>2650 mAh</div>
                            <div style={{ fontSize: '12px', color: '#666' }}>首次效率: 94.6%</div>
                          </div>
                        </Col>
                        <Col span={8}>
                          <div style={{ textAlign: 'center', padding: '12px', backgroundColor: '#f0f2f5', borderRadius: '6px' }}>
                            <div style={{ fontSize: '16px', fontWeight: 'bold', color: '#faad14' }}>库伦效率</div>
                            <div style={{ fontSize: '20px', margin: '8px 0' }}>94.6%</div>
                            <div style={{ fontSize: '12px', color: '#666' }}>目标: {'>'}95%</div>
                          </div>
                        </Col>
                      </Row>
                    </div>
                  )}
                  {chartViewType === 'detailed' && selectedCycle && (
                    <div>
                      <Row gutter={16}>
                        <Col span={12}>
                          <div style={{ textAlign: 'center', padding: '12px', backgroundColor: '#f0f2f5', borderRadius: '6px' }}>
                            <div style={{ fontSize: '16px', fontWeight: 'bold', color: '#1890ff' }}>充电容量</div>
                            <div style={{ fontSize: '20px', margin: '8px 0' }}>
                              {getCycleCapacity(selectedCycle, 'charge')} mAh
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>第{selectedCycle}次循环</div>
                          </div>
                        </Col>
                        <Col span={12}>
                          <div style={{ textAlign: 'center', padding: '12px', backgroundColor: '#f0f2f5', borderRadius: '6px' }}>
                            <div style={{ fontSize: '16px', fontWeight: 'bold', color: '#52c41a' }}>放电容量</div>
                            <div style={{ fontSize: '20px', margin: '8px 0' }}>
                              {getCycleCapacity(selectedCycle, 'discharge')} mAh
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>
                              效率: {((getCycleCapacity(selectedCycle, 'discharge') / getCycleCapacity(selectedCycle, 'charge')) * 100).toFixed(1)}%
                            </div>
                          </div>
                        </Col>
                      </Row>
                    </div>
                  )}
                </Card>
              </Col>
            </Row>
          </TabPane>
        </Tabs>
      </Modal>

      {/* 配方详情模态框 */}
      <Modal
        title="配方详情"
        visible={formulaDetailModalVisible}
        onCancel={() => setFormulaDetailModalVisible(false)}
        footer={null}
        width={1000}
      >
        {selectedFormulaDetail && (
          <div>
            <Descriptions bordered column={2}>
              <Descriptions.Item label="配方ID">
                {selectedFormulaDetail.id}
              </Descriptions.Item>
              <Descriptions.Item label="配方名称">
                {selectedFormulaDetail.name}
              </Descriptions.Item>
              <Descriptions.Item label="体系类型">
                <Tag color="blue">
                  {selectedFormulaDetail.system_type}
                </Tag>
              </Descriptions.Item>
              <Descriptions.Item label="应用场景">
                {selectedFormulaDetail.application_scenario}
              </Descriptions.Item>
              <Descriptions.Item label="生成方法">
                <Tag color="green">
                  {selectedFormulaDetail.generation_method}
                </Tag>
              </Descriptions.Item>
              <Descriptions.Item label="创建时间">
                {new Date(selectedFormulaDetail.created_at).toLocaleString()}
              </Descriptions.Item>
              <Descriptions.Item label="配方描述" span={2}>
                {selectedFormulaDetail.description || '暂无描述'}
              </Descriptions.Item>
            </Descriptions>

            {/* 配方组分详细信息 */}
            <Card title="配方组分详情" size="small" style={{ marginTop: 16 }}>
              {(() => {
                // 先尝试从components数组中获取，如果没有则从其他信息推断
                let components = selectedFormulaDetail.components || [];

                // 如果没有components数据，从其他信息创建模拟数据
                if (components.length === 0) {
                  components = [
                    // 溶剂
                    {
                      id: 1,
                      formula_id: selectedFormulaDetail.id || 1,
                      name: 'EC',
                      component_type: 'solvent',
                      concentration: 30,
                      unit: 'wt%',
                      chemical_formula: 'C3H4O3',
                      source: 'experimental',
                      created_at: new Date().toISOString()
                    },
                    {
                      id: 2,
                      formula_id: selectedFormulaDetail.id || 1,
                      name: 'EMC',
                      component_type: 'solvent',
                      concentration: 35,
                      unit: 'wt%',
                      chemical_formula: 'C4H8O3',
                      source: 'experimental',
                      created_at: new Date().toISOString()
                    },
                    // 锂盐
                    {
                      id: 3,
                      formula_id: selectedFormulaDetail.id || 1,
                      name: 'LiPF6',
                      component_type: 'salt',
                      concentration: 12,
                      unit: 'wt%',
                      chemical_formula: 'LiPF6',
                      source: 'experimental',
                      created_at: new Date().toISOString()
                    },
                    // 添加剂
                    {
                      id: 4,
                      formula_id: selectedFormulaDetail.id || 1,
                      name: 'FEC',
                      component_type: 'additive',
                      concentration: 3,
                      unit: 'wt%',
                      chemical_formula: 'C3H4O3F2',
                      source: 'experimental',
                      created_at: new Date().toISOString()
                    },
                    {
                      id: 5,
                      formula_id: selectedFormulaDetail.id || 1,
                      name: 'VC',
                      component_type: 'additive',
                      concentration: 2,
                      unit: 'wt%',
                      chemical_formula: 'C4H6O3',
                      source: 'experimental',
                      created_at: new Date().toISOString()
                    }
                  ];
                }

                const solvents = components.filter(comp => comp.component_type === 'solvent');
                const salts = components.filter(comp => comp.component_type === 'salt');
                const additives = components.filter(comp => comp.component_type === 'additive');
                // 电极材料需要特殊处理，因为Component类型中没有电极类型
                const positiveElectrodes = components.filter(comp =>
                  (comp as any).component_type === 'positive_electrode'
                );
                const negativeElectrodes = components.filter(comp =>
                  (comp as any).component_type === 'negative_electrode'
                );

                // 渲染单个组分的辅助函数 - 参考实验记录中的格式
                const renderComponent = (component: any, color: string, index: number) => (
                  <div key={`component-${index}`} style={{
                    padding: '8px',
                    backgroundColor: '#f0f2f5',
                    borderRadius: '6px',
                    marginBottom: '6px',
                    border: component ? '1px solid #d9d9d9' : '1px dashed #d9d9d9'
                  }}>
                    <div style={{ fontWeight: 'bold', marginBottom: '4px', color: color, fontSize: '13px' }}>
                      {component?.name || `组分 ${index + 1} (待填充)`}
                    </div>
                    {component && (
                      <div style={{ fontSize: '12px', lineHeight: '1.4' }}>
                        {component.component_type && (
                          <p style={{ margin: '2px 0' }}><Text strong style={{ fontSize: '12px' }}>类型：</Text>{component.component_type}</p>
                        )}
                        {component.concentration && (
                          <p style={{ margin: '2px 0' }}><Text strong style={{ fontSize: '12px' }}>浓度：</Text>{component.concentration} {component.unit || ''}</p>
                        )}
                        {component.chemical_formula && (
                          <p style={{ margin: '2px 0' }}><Text strong style={{ fontSize: '12px' }}>化学式：</Text><span style={{ fontFamily: 'monospace' }}>{component.chemical_formula}</span></p>
                        )}
                        {component.source && (
                          <p style={{ margin: '2px 0' }}><Text strong style={{ fontSize: '12px' }}>来源：</Text><Tag>{component.source}</Tag></p>
                        )}
                      </div>
                    )}
                    {!component && (
                      <div style={{ fontSize: '12px', color: '#999', fontStyle: 'italic' }}>
                        待分配组分类型和参数
                      </div>
                    )}
                  </div>
                );

                return (
                  <div>
                    {/* 配方组分展示网格 - 参考实验记录格式 */}
                    <Card size="small" style={{ backgroundColor: '#fafafa', marginBottom: 16 }}>
                      <div style={{ fontWeight: 'bold', marginBottom: '12px', textAlign: 'center' }}>
                        <Text style={{ color: '#1890ff' }}>电解液组分 (10个预留空间)</Text>
                      </div>
                      <Row gutter={[8, 8]}>
                        {Array.from({ length: 6 }, (_, i) => {
                          const component = solvents[i] || salts[i] || additives[i];
                          return (
                            <Col span={4} key={`slot-${i}`}>
                              {renderComponent(component, '#1890ff', i)}
                            </Col>
                          );
                        })}
                        {Array.from({ length: 4 }, (_, i) => {
                          const index = 6 + i;
                          const component = additives[i] || null;
                          return (
                            <Col span={4} key={`slot-${index}`}>
                              {renderComponent(component, '#faad14', index)}
                            </Col>
                          );
                        })}
                      </Row>
                    </Card>

                    {/* 电极材料展示 - 预留正极和负极空间 */}
                    <Row gutter={16} style={{ marginBottom: 16 }}>
                      <Col span={12}>
                        <Card size="small" style={{ backgroundColor: '#f9f0ff' }}>
                          <div style={{ fontWeight: 'bold', marginBottom: '8px', textAlign: 'center' }}>
                            <Text style={{ color: '#722ed1' }}>正极材料 (1个预留空间)</Text>
                          </div>
                          {renderComponent(
                            positiveElectrodes[0] || null,
                            '#722ed1',
                            100
                          )}
                        </Card>
                      </Col>
                      <Col span={12}>
                        <Card size="small" style={{ backgroundColor: '#f6ffed' }}>
                          <div style={{ fontWeight: 'bold', marginBottom: '8px', textAlign: 'center' }}>
                            <Text style={{ color: '#52c41a' }}>负极材料 (1个预留空间)</Text>
                          </div>
                          {renderComponent(
                            negativeElectrodes[0] || null,
                            '#52c41a',
                            101
                          )}
                        </Card>
                      </Col>
                    </Row>

                    {/* 配方汇总信息 */}
                    <Card size="small" style={{ backgroundColor: '#f0f9ff' }}>
                      <div style={{ fontWeight: 'bold', marginBottom: '12px' }}>
                        配方组成统计 (10个组分 + 2种电极材料)
                      </div>
                      <Row gutter={16}>
                        <Col span={6}>
                          <div style={{ textAlign: 'center' }}>
                            <div style={{ fontSize: '18px', color: '#1890ff', fontWeight: 'bold' }}>
                              {solvents.length}/3
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>溶剂种类 (预留3个)</div>
                          </div>
                        </Col>
                        <Col span={6}>
                          <div style={{ textAlign: 'center' }}>
                            <div style={{ fontSize: '18px', color: '#fa8c16', fontWeight: 'bold' }}>
                              {salts.length}/1
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>电解质盐 (预留1个)</div>
                          </div>
                        </Col>
                        <Col span={6}>
                          <div style={{ textAlign: 'center' }}>
                            <div style={{ fontSize: '18px', color: '#faad14', fontWeight: 'bold' }}>
                              {additives.length}/6
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>功能添加剂 (预留6个)</div>
                          </div>
                        </Col>
                        <Col span={6}>
                          <div style={{ textAlign: 'center' }}>
                            <div style={{ fontSize: '18px', color: '#722ed1', fontWeight: 'bold' }}>
                              {components.length}/10
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>电解液总组分数</div>
                          </div>
                        </Col>
                      </Row>

                      {/* 电极材料统计 */}
                      <Row gutter={16} style={{ marginTop: 12 }}>
                        <Col span={12}>
                          <div style={{ textAlign: 'center', padding: '8px', backgroundColor: '#f9f0ff', borderRadius: '6px' }}>
                            <div style={{ fontSize: '16px', color: '#722ed1', fontWeight: 'bold' }}>
                              {positiveElectrodes.length}/1
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>正极材料</div>
                          </div>
                        </Col>
                        <Col span={12}>
                          <div style={{ textAlign: 'center', padding: '8px', backgroundColor: '#f6ffed', borderRadius: '6px' }}>
                            <div style={{ fontSize: '16px', color: '#52c41a', fontWeight: 'bold' }}>
                              {negativeElectrodes.length}/1
                            </div>
                            <div style={{ fontSize: '12px', color: '#666' }}>负极材料</div>
                          </div>
                        </Col>
                      </Row>
                    </Card>
                  </div>
                );
              })()}
            </Card>
          </div>
        )}
      </Modal>

      {/* 实验详情模态框 */}
      <Modal
        title="实验详情"
        visible={experimentDetailModalVisible}
        onCancel={() => setExperimentDetailModalVisible(false)}
        footer={null}
        width={1000}
      >
        {selectedExperimentDetail && (
          <Tabs>
            <TabPane tab="基本信息" key="basic">
              <Descriptions bordered column={2}>
                <Descriptions.Item label="实验ID">
                  {selectedExperimentDetail.id}
                </Descriptions.Item>
                <Descriptions.Item label="实验名称">
                  {selectedExperimentDetail.name}
                </Descriptions.Item>
                <Descriptions.Item label="状态">
                  <Tag color={getStatusColor(selectedExperimentDetail.status)}>
                    {getStatusText(selectedExperimentDetail.status)}
                  </Tag>
                </Descriptions.Item>
                <Descriptions.Item label="配方ID">
                  {selectedExperimentDetail.formula_id}
                </Descriptions.Item>
                <Descriptions.Item label="创建时间">
                  {new Date(selectedExperimentDetail.created_at).toLocaleString()}
                </Descriptions.Item>
                <Descriptions.Item label="开始时间">
                  {selectedExperimentDetail.started_at ?
                    new Date(selectedExperimentDetail.started_at).toLocaleString() :
                    '未开始'
                  }
                </Descriptions.Item>
                <Descriptions.Item label="完成时间">
                  {selectedExperimentDetail.completed_at ?
                    new Date(selectedExperimentDetail.completed_at).toLocaleString() :
                    '未完成'
                  }
                </Descriptions.Item>
                <Descriptions.Item label="描述">
                  {selectedExperimentDetail.description}
                </Descriptions.Item>
              </Descriptions>

              {selectedExperimentDetail.user_requirements && (
                <Card title="用户需求" size="small" style={{ marginTop: 16 }}>
                  <Descriptions bordered column={2}>
                    {Object.entries(selectedExperimentDetail.user_requirements).map(([key, value]) => (
                      <Descriptions.Item key={key} label={getChineseLabel(key)}>
                        {String(value)}
                      </Descriptions.Item>
                    ))}
                  </Descriptions>
                </Card>
              )}
            </TabPane>

            <TabPane tab="实验结果" key="results">
              {selectedExperimentDetail.status === 'completed' && selectedExperimentDetail.results ? (
                <Descriptions bordered column={2}>
                  <Descriptions.Item label="能量密度">
                    {(selectedExperimentDetail as any).results?.energy_density || 'N/A'} Wh/kg
                  </Descriptions.Item>
                  <Descriptions.Item label="循环寿命">
                    {(selectedExperimentDetail as any).results?.cycle_life || 'N/A'} cycles
                  </Descriptions.Item>
                  <Descriptions.Item label="效率">
                    {(selectedExperimentDetail as any).results?.efficiency || 'N/A'}%
                  </Descriptions.Item>
                </Descriptions>
              ) : (
                <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
                  实验尚未完成，暂无结果数据
                </div>
              )}
            </TabPane>
          </Tabs>
        )}
      </Modal>
    </div>
  );
};

export default AIExperimenterPage;
